import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import { UserManager } from 'oidc-client';
import { Cookies } from 'universal-cookie';

const config = {
  authority: 'https://your-auth-server-url',
  client_id: 'your-client-id',
  redirect_uri: 'http://localhost:3000/callback',
  response_type: 'code',
  scope: 'openid profile email',
  post_logout_redirect_uri: 'http://localhost:3000',
};

const userManager = new UserManager(config);
const cookies = new Cookies();

const App = () => {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const handleCallback = async () => {
      const params = new URLSearchParams(window.location.search);
      const code = params.get('code');

      if (code) {
        const response = await userManager.signinRedirectCallback();
        const idToken = response && response.id_token;

        if (idToken) {
          const decodedToken = userManager.getUser().profile;
          setUser(decodedToken);
          cookies.set('user', decodedToken, { path: '/'});
        }
      }
    };

    handleCallback();
  }, []);

  const handleLogin = () => {
    userManager.signinRedirect();
  };

  const handleLogout = () => {
    userManager.signoutRedirect();
    cookies.remove('user');
    setUser(null);
  };

  return (
    <div>
      {user ? (
        <div>
          <h2>Welcome, {user.name}</h2>
          <button onClick={handleLogout}>Logout</button>
        </div>
      ) : (
        <button onClick={handleLogin}>Login</button>
      )}
    </div>
  );
};

export default App;

